package model;
import java.awt.Color;
import java.util.Random;
import java.util.ArrayList;
import java.util.List;
public class Gast extends Persoon {
    private static final Random RANDOM = new Random();
    private static final double SPEED = 0.5;
    private static final int LIFT_X = 0;   // Column 1 in layout = 0 in gast coords
    private static final int TRAP_X = 8;   // Column 9 in layout = 8 in gast coords
    private double x, y;
    private double destX, destY;
    private double finalDestX, finalDestY;
    private int maxX, maxY;
    private Hotel hotel;
    private Color kleur;
    private enum State {
        WANDELEN, NAAR_VERVOER, IN_VERVOER, VAN_VERVOER_WEG
    }
    private State state = State.WANDELEN;
    private int vervoerX = LIFT_X;
    public Gast(String naam, int startX, int startY) {
        super(naam, "Gast");
        this.x = startX + 0.5;
        this.y = startY + 0.5;
        this.destX = x;
        this.destY = y;
        this.finalDestX = x;
        this.finalDestY = y;
        this.kleur = new Color(RANDOM.nextInt(256), RANDOM.nextInt(256), RANDOM.nextInt(256));
    }
    @Override
    public void onTick() {
        System.out.println("[Gast] " + getNaam() + " beweegt naar (" + destX + ", " + destY + ") - nu op (" + x + ", " + y + ")");
        beweegStap();
    }
    private void beweegStap() {
        double dx = destX - x;
        double dy = destY - y;
        double distance = Math.sqrt(dx * dx + dy * dy);
        if (distance < SPEED) {
            handleStateTransition();
            return;
        }
        double dirX = dx / distance;
        double dirY = dy / distance;
        x += dirX * SPEED;
        y += dirY * SPEED;
        x = Math.max(0.5, Math.min(x, maxX - 0.5));
        y = Math.max(0.5, Math.min(y, maxY - 0.5));
    }
    private void handleStateTransition() {
        switch (state) {
            case WANDELEN:
                kiesNieuwebestemming();
                int currentFloor = (int) y;
                int newFloor = (int) finalDestY;
                if (currentFloor != newFloor) {
                    this.vervoerX = RANDOM.nextBoolean() ? LIFT_X : TRAP_X;
                    this.destX = vervoerX + 0.5;
                    this.destY = y;
                    this.state = State.NAAR_VERVOER;
                } else {
                    this.destX = finalDestX;
                    this.destY = finalDestY;
                }
                break;
            case NAAR_VERVOER:
                this.destX = vervoerX + 0.5;
                this.destY = finalDestY;
                this.state = State.IN_VERVOER;
                break;
            case IN_VERVOER:
                this.destX = finalDestX;
                this.destY = finalDestY;
                this.state = State.VAN_VERVOER_WEG;
                break;
            case VAN_VERVOER_WEG:
                this.state = State.WANDELEN;
                handleStateTransition();
                break;
        }
    }
    private void kiesNieuwebestemming() {
        if (hotel == null) {
            this.finalDestX = RANDOM.nextInt(Math.max(1, maxX - 1)) + 0.5;
            this.finalDestY = RANDOM.nextInt(Math.max(1, maxY - 1)) + 0.5;
            return;
        }
        List<Area> areas = hotel.getAreas();
        if (areas.isEmpty()) return;
        List<Area> validAreas = new ArrayList<>();
        for (Area area : areas) {
            if (!area.getAreaType().equals("Lift") && !area.getAreaType().equals("Staircase")) {
                validAreas.add(area);
            }
        }
        if (validAreas.isEmpty()) return;
        Area target = validAreas.get(RANDOM.nextInt(validAreas.size()));

        // Area.getX/Y() zijn 1-indexed, converteer naar 0-indexed voor gast
        int randomX = (target.getX() - 1) + RANDOM.nextInt(Math.max(1, target.getBreedte()));
        int randomY = (target.getY() - 1) + RANDOM.nextInt(Math.max(1, target.getHoogte()));

        this.finalDestX = randomX + 0.5;
        this.finalDestY = randomY + 0.5;
    }
    public void setGridBounds(int maxX, int maxY) {
        this.maxX = maxX;
        this.maxY = maxY;
    }
    public void setHotel(Hotel hotel) {
        this.hotel = hotel;
    }
    public double getX() { return x; }
    public double getY() { return y; }
    public Color getKleur() { return kleur; }
}

package model;
import java.awt.Color;
import java.util.Random;
import java.util.ArrayList;
import java.util.List;

/**
 * GAST - Hotelgast die rond loopt, in/uit lift stapt en verdiepingen verandert
 */
public class Gast extends Persoon {
    private static final Random RANDOM = new Random();
    private static final double SPEED = 0.5;
    private static final double LIFT_WAIT_X = 1.5;  // Buiten schacht: wachten op lift
    private static final double TRAP_X = 8.5;       // Trap X-positie (kolom 9, dus 8.5)

    // === POSITIE ===
    private double x, y;           // Huidige positie
    private double destX, destY;   // Intermediate doel (bijv. naar lift toe)
    private double finalDestX, finalDestY; // Echte doel (kamer/restaurant)
    private int maxX, maxY;

    // === HOTEL & LIFT ===
    private Hotel hotel;
    private Lift lift;             // Referentie naar de lift
    private boolean inLift = false; // Zit gast in lift?
    private boolean usesTrap = false; // Gebruikt deze gast de trap?

    // === VISUAAL ===
    private Color kleur;

    // === TOESTANDEN ===
    private enum State {
        WANDELEN,           // Loopt normaal rond
        NAAR_LIFT_WACHTEN,  // Loopt naar lift wachtplek (X=1.5, zelfde Y)
        WACHTEN_OP_LIFT,    // Staat stil en wacht tot lift aankomt
        IN_LIFT,            // Zit in lift
        NAAR_DOEL           // Na lift: loopt naar eindbestemming
    }
    private State state = State.WANDELEN;

    public Gast(String naam, int startX, int startY) {
        super(naam, "Gast");
        this.x = startX + 0.5;
        this.y = startY + 0.5;
        this.destX = x;
        this.destY = y;
        this.finalDestX = x;
        this.finalDestY = y;
        this.kleur = new Color(RANDOM.nextInt(256), RANDOM.nextInt(256), RANDOM.nextInt(256));
    }

    @Override
    public void onTick() {
        // === NORMALE BEWEGING (niet in lift) ===
        if (!inLift) {
            beweegStap();
        } else {
            // === IN LIFT: VOLG LIFT-POSITIE ===
            if (lift != null) {
                this.x = lift.getX();
                this.y = lift.getY();

                // === CHECK OF GAST UIT MOET STAPPEN ===
                int liftFloor = (int) lift.getY();
                int destFloor = (int) finalDestY;

                // Lift op doel en stilstaand?
                if (liftFloor == destFloor && lift.isIdle()) {
                    // Stap uit!
                    lift.verwijderGast(this);
                    this.inLift = false;
                    this.state = State.NAAR_DOEL;
                    this.destX = finalDestX;
                    this.destY = finalDestY;
                    System.out.println("[Gast] " + getNaam() + " stapt uit lift op verdieping " + (int)y);
                }
            }
        }
    }

    /**
     * Normale beweging als gast niet in lift zit
     */
    private void beweegStap() {
        double dx = destX - x;
        double dy = destY - y;
        double distance = Math.sqrt(dx * dx + dy * dy);

        // Aangekomen op doel?
        if (distance < SPEED) {
            handleStateTransition();
            return;
        }

        // Zet stap in richting van doel
        double dirX = dx / distance;
        double dirY = dy / distance;
        x += dirX * SPEED;
        y += dirY * SPEED;

        // Zorg dat gast binnen hotel blijft
        x = Math.max(0.5, Math.min(x, maxX - 0.5));
        y = Math.max(0.5, Math.min(y, maxY - 0.5));
    }

    /**
     * Verwerk toestandsovergangen
     */
    private void handleStateTransition() {
        switch (state) {
            case WANDELEN:
                // === FASE 1: KIES NIEUW DOEL ===
                kiesNieuwebestemming();
                int currentFloor = (int) y;
                int newFloor = (int) finalDestY;

                if (currentFloor != newFloor) {
                    // === ANDER VERDIEPING: KIES LIFT OF TRAP ===
                    // 50% kans trap, 50% kans lift
                    this.usesTrap = RANDOM.nextBoolean();

                    if (usesTrap) {
                        // TRAP GEBRUIKEN
                        this.destX = TRAP_X;
                        this.destY = y;  // Zelfde verdieping, maar naar trap toe
                        this.state = State.NAAR_LIFT_WACHTEN;
                        System.out.println("[Gast] " + getNaam() + " loopt naar TRAP (verdieping " + currentFloor + " → " + newFloor + ")");
                    } else {
                        // LIFT GEBRUIKEN
                        this.destX = LIFT_WAIT_X;
                        this.destY = y;  // Zelfde verdieping, maar naar lift toe
                        this.state = State.NAAR_LIFT_WACHTEN;
                        System.out.println("[Gast] " + getNaam() + " loopt naar LIFT (verdieping " + currentFloor + " → " + newFloor + ")");
                    }
                } else {
                    // ZELFDE VERDIEPING: direct naar doel
                    this.destX = finalDestX;
                    this.destY = finalDestY;
                    this.state = State.NAAR_DOEL;
                }
                break;

            case NAAR_LIFT_WACHTEN:
                // === FASE 2: GAST LOOPT NAAR LIFT/TRAP WACHTPLEK ===
                double targetX = usesTrap ? TRAP_X : LIFT_WAIT_X;

                if (Math.abs(x - targetX) < 0.2) {
                    this.x = targetX;  // Lock positie
                    this.state = State.WACHTEN_OP_LIFT;
                    System.out.println("[Gast] " + getNaam() + " wacht op " + (usesTrap ? "TRAP" : "LIFT") + " op verdieping " + (int)y);
                }
                break;

            case WACHTEN_OP_LIFT:
                // === FASE 3: WACHTEN OP VERVOER ===
                if (usesTrap) {
                    // === TRAP: GAST GAAT ZELF OMHOOG/OMLAAG ===
                    // Trap mag direct gebruikt worden
                    this.destX = finalDestX;
                    this.destY = finalDestY;
                    this.state = State.NAAR_DOEL;
                    System.out.println("[Gast] " + getNaam() + " stapt op TRAP en gaat naar verdieping " + (int)finalDestY);
                } else {
                    // === LIFT: WACHT TOT LIFT AANKOMT ===
                    if (lift != null && Math.abs(lift.getY() - this.y) < 0.2 && lift.isIdle()) {
                        // LIFT IS HIER! Stap in
                        if (lift.voegGastToe(this)) {
                            this.inLift = true;
                            this.state = State.IN_LIFT;
                            // Roep lift op naar doel
                            lift.roepNaar((int) finalDestY);
                            System.out.println("[Gast] " + getNaam() + " stapt in LIFT op verdieping " + (int)y);
                        }
                    }
                }
                break;

            case IN_LIFT:
                // === FASE 4: IN LIFT - EXIT WORDT AFGEHANDELD IN onTick() ===
                // Niets nodig, gast volgt lift en stapt uit in onTick()
                break;

            case NAAR_DOEL:
                // === FASE 5: LOOPT NAAR EINDBESTEMMING ===
                // Check: zijn we aangekomen?
                double dx = finalDestX - x;
                double dy = finalDestY - y;
                double distance = Math.sqrt(dx * dx + dy * dy);

                if (distance < 0.5) {
                    // AANGEKOMEN! Terug naar WANDELEN
                    this.state = State.WANDELEN;
                    System.out.println("[Gast] " + getNaam() + " is aangekomen op bestemming " + (int)x + "," + (int)y);
                }
                break;
        }
    }

    /**
     * Kies willekeurig nieuw doel
     */
    private void kiesNieuwebestemming() {
        if (hotel == null) {
            this.finalDestX = RANDOM.nextInt(Math.max(1, maxX - 1)) + 0.5;
            this.finalDestY = RANDOM.nextInt(Math.max(1, maxY - 1)) + 0.5;
            return;
        }

        List<Area> areas = hotel.getAreas();
        if (areas.isEmpty()) return;

        // Filter: niet naar lift/trap/schacht
        List<Area> validAreas = new ArrayList<>();
        for (Area area : areas) {
            String type = area.getAreaType();
            if (!type.equals("Lift") && !type.equals("Staircase") && !type.equals("Schacht")) {
                validAreas.add(area);
            }
        }

        if (validAreas.isEmpty()) return;

        // Kies willekeurig
        Area target = validAreas.get(RANDOM.nextInt(validAreas.size()));

        int randomX = (target.getX() - 1) + RANDOM.nextInt(Math.max(1, target.getBreedte()));
        int randomY = (target.getY() - 1) + RANDOM.nextInt(Math.max(1, target.getHoogte()));

        this.finalDestX = randomX + 0.5;
        this.finalDestY = randomY + 0.5;
    }

    /**
     * BELANGRIJK: Lift zet gast positie wanneer in lift
     */
    public void setLiftPosition(double liftX, double liftY) {
        if (inLift) {
            this.x = liftX;
            this.y = liftY;
        }
    }

    // === SETTERS ===
    public void setGridBounds(int maxX, int maxY) {
        this.maxX = maxX;
        this.maxY = maxY;
    }

    public void setHotel(Hotel hotel) {
        this.hotel = hotel;
    }

    public void setLift(Lift lift) {
        this.lift = lift;
    }

    // === GETTERS ===
    public double getX() { return x; }
    public double getY() { return y; }
    public Color getKleur() { return kleur; }
    public boolean isInLift() { return inLift; }
}

package model;

import model.TickListener;

// Lift is ook een entiteit die alleen beweegt per tick
public class Lift implements TickListener {

    private int huidigeVerdieping = 0;
    private int doelVerdieping = 5;

    @Override
    public void onTick() {

        // Beweging alleen tijdens tick
        beweeg();

        System.out.println("Lift op verdieping: " + huidigeVerdieping);
    }

    private void beweeg() {

        // Lift beweegt 1 verdieping per tick
        if (huidigeVerdieping < doelVerdieping) {
            huidigeVerdieping++;
        } else if (huidigeVerdieping > doelVerdieping) {
            huidigeVerdieping--;
        }
    }

    public void setDoelVerdieping(int doel) {
        this.doelVerdieping = doel;
    }
}

package model;

import java.util.ArrayList;
import java.util.List;

/**
 * LIFT - Beweegt omhoog/omlaag in de schacht
 * Personen kunnen erin stappen en naar andere verdiepingen gaan.
 * De lift brengt passagiers naar hun doel-verdieping.
 */
public class Lift implements TickListener {

    // === POSITIE ===
    private double x, y;           // Huidige coördinaten (X blijft constant, Y verandert)
    private double targetY;        // Doelverdieping waar lift heen gaat
    private int schachtMinY;       // Onderste verdieping van schacht
    private int schachtMaxY;       // Bovenste verdieping van schacht

    // === PASSAGIERS ===
    private List<Gast> passagiers; // Personen in de lift
    private static final int MAX_CAPACITY = 3; // Max personen

    // === BEWEGING ===
    private static final double LIFT_SPEED = 0.5; // Hoe snel lift beweegt

    // === STAAT ===
    private enum LiftState {
        IDLE,         // Stil wachten
        MOVING_UP,    // Naar boven
        MOVING_DOWN   // Naar beneden
    }
    private LiftState state = LiftState.IDLE;

    // === AUTOMATISCHE RONDE ===
    private int nextAutoFloor = 1;  // Volgende verdieping die lift automatisch gaat bezoeken

    /**
     * Constructor - initialiseer lift
     * startX: X-positie in de schacht (meestal 0.5)
     * startY: Beginhoogte
     * schachtMinY/MaxY: Grenzen van schacht
     */
    public Lift(double startX, double startY, int schachtMinY, int schachtMaxY) {
        this.x = startX;
        this.y = startY;
        this.targetY = startY;
        this.schachtMinY = schachtMinY;
        this.schachtMaxY = schachtMaxY;
        this.passagiers = new ArrayList<>();
        System.out.println("[Lift] Geïnitialiseerd op positie (" + x + ", " + y + ")");
    }

    /**
     * Roep lift op naar een bepaalde verdieping
     */
    public void roepNaar(int verdieping) {
        // Converteer verdieping (1-7) naar Y-coördinaat
        this.targetY = (verdieping - 1) + 0.5;
        System.out.println("[Lift] Geroepen naar verdieping " + verdieping);
    }

    /**
     * Gast stapt in de lift (alleen als lift op dezelfde verdieping is!)
     */
    public boolean voegGastToe(Gast gast) {
        // Check: zit gast op dezelfde verdieping als lift?
        if (Math.abs(gast.getY() - this.y) > 0.1) {
            return false; // Nee, gast kan niet instappen
        }

        // Check: is lift vol?
        if (passagiers.size() >= MAX_CAPACITY) {
            return false;
        }

        // Voeg gast toe
        passagiers.add(gast);
        System.out.println("[Lift] " + gast.getNaam() + " stapt in op verdieping " + (int)y + " | Passagiers nu: " + passagiers.size());
        return true;
    }

    /**
     * Gast stapt uit de lift
     */
    public void verwijderGast(Gast gast) {
        if (passagiers.remove(gast)) {
            System.out.println("[Lift] " + gast.getNaam() + " stapt uit op verdieping " + (int)y + " | Passagiers nu: " + passagiers.size());
        }
    }

    /**
     * Geef alle passagiers terug
     */
    public List<Gast> getPassagiers() {
        return new ArrayList<>(passagiers);
    }

    /**
     * Check of lift vol is
     */
    public boolean isVol() {
        return passagiers.size() >= MAX_CAPACITY;
    }

    // === TICK LISTENER - Wordt elke HTE-tick aangeroepen ===
    @Override
    public void onTick() {
        // === FASE 1: AUTO-RONDE (lift maakt continu ronde) ===
        // BELANGRIJK: Lift gaat door, zelfs met passagiers!
        if (state == LiftState.IDLE) {
            // Lift staat stil -> ga volgende verdieping bezoeken
            this.targetY = (nextAutoFloor - 1) + 0.5;
            System.out.println("[Lift] Gaat naar verdieping " + nextAutoFloor + " (Y=" + String.format("%.1f", targetY) + ")");

            // Volgende keer volgende verdieping
            nextAutoFloor++;
            if (nextAutoFloor > schachtMaxY + 1) {
                nextAutoFloor = 1;  // Terug naar beneden
            }
        }

        // === FASE 2: BEWEGING NAAR TARGET ===
        if (Math.abs(targetY - y) < LIFT_SPEED) {
            // Aangekomen!
            y = targetY;
            state = LiftState.IDLE;
            System.out.println("[Lift] AANGEKOMEN op Y=" + String.format("%.1f", y) + " (Passagiers: " + passagiers.size() + ")");
        } else if (targetY > y) {
            // Omhoog
            state = LiftState.MOVING_UP;
            y += LIFT_SPEED;
        } else if (targetY < y) {
            // Omlaag
            state = LiftState.MOVING_DOWN;
            y -= LIFT_SPEED;
        }

        // Zorg dat lift binnen grenzen blijft
        y = Math.max(schachtMinY + 0.5, Math.min(y, schachtMaxY + 0.5));

        // === FASE 3: PASSAGIERS MEENEMEN ===
        for (Gast gast : passagiers) {
            gast.setLiftPosition(this.x, this.y);
        }
    }

    // === GETTERS ===
    public double getX() { return x; }
    public double getY() { return y; }
    public int getVerdieping() { return (int) y; }
    public boolean isIdle() { return state == LiftState.IDLE; }
    public int getPassagierCount() { return passagiers.size(); }
}

package model;

import model.SimulationClock;
import model.HTEClock;
import model.TickListener;
import model.Persoon;
import ui.HotelPanel;

/**
 * Simulator - Stuurt de simulatie aan via HTE-ticks
 */
public class Simulator {

    private boolean running;
    private HotelPanel hotelPanel;
    private Hotel hotel;
    private SimulationClock clock;
    private HTEClock hteClock;

    private static final long TICK_INTERVAL = 100; // 100 ms

    public Simulator(Hotel hotel, HotelPanel hotelPanel) {
        this.hotel = hotel;
        this.hotelPanel = hotelPanel;
        this.running = false;
        this.clock = new SimulationClock(TICK_INTERVAL);
        this.hteClock = new HTEClock();

        // Registreer alle personen als listeners op HTEClock
        for (Persoon p : hotel.getPersonen()) {
            if (p instanceof TickListener) {
                hteClock.addListener((TickListener) p);
            }
        }
    }

    public void start() {
        running = true;
        clock.start(); // start interne tijdmeting
        hotelPanel.setRunning(true);
        System.out.println("[Simulator] Simulatie gestart");
    }

    public void pause() {
        running = false;
        clock.stop();
        hotelPanel.setRunning(false);
        System.out.println("[Simulator] Simulatie gepauzeerd");
    }

    public boolean isRunning() {
        return running;
    }

    public SimulationClock getClock() {
        return clock;
    }

    public HTEClock getHteClock() {
        return hteClock;
    }

    public void resetClock() {
        clock.reset();
        hteClock = new HTEClock();
        for (Persoon p : hotel.getPersonen()) {
            if (p instanceof TickListener) {
                hteClock.addListener((TickListener) p);
            }
        }
    }

    /**
     * HOOFDMETHODE: Wordt aangeroepen door Timer in main
     */
    public void tick() {

        // Check of er een echte HTE-tick plaatsvindt
        if (running && clock.tick()) {
            System.out.println("[Simulator] HTE-tick #" + clock.getTimestep());

            // Roep HTEClock.tick() aan (die roept alle listeners.onTick() aan)
            hteClock.tick();
        }

        // UI altijd updaten (ook bij pauze)
        hotelPanel.repaint();
    }
}

package model;

import model.SimulationClock;
import model.HTEClock;
import model.TickListener;
import model.Persoon;
import ui.HotelPanel;

/**
 * Simulator - Stuurt de simulatie aan via HTE-ticks
 * Beheert lift en alle gasten
 */
public class Simulator {

    private boolean running;
    private HotelPanel hotelPanel;
    private Hotel hotel;
    private SimulationClock clock;
    private HTEClock hteClock;
    private Lift lift;             // De lift object

    private static final long TICK_INTERVAL = 100; // 100 ms

    public Simulator(Hotel hotel, HotelPanel hotelPanel) {
        this.hotel = hotel;
        this.hotelPanel = hotelPanel;
        this.running = false;
        this.clock = new SimulationClock(TICK_INTERVAL);
        this.hteClock = new HTEClock();

        // === INITIALISEER LIFT ===
        // Zoek de Schacht area (waar lift beweegt)
        Area schachtArea = null;
        for (Area area : hotel.getAreas()) {
            if (area.getAreaType().equals("Schacht")) {
                schachtArea = area;
                break;
            }
        }

        if (schachtArea != null) {
            // Maak lift aan in schacht
            // X = schacht X-coördinaat + 0.5 (midden van vakje)
            // Y start op eerste verdieping
            double liftX = (schachtArea.getX() - 1) + 0.5;
            double liftY = (schachtArea.getY() - 1) + 0.5;
            int minY = schachtArea.getY() - 1;
            int maxY = schachtArea.getY() + schachtArea.getHoogte() - 2;

            this.lift = new Lift(liftX, liftY, minY, maxY);
            System.out.println("[Simulator] Lift geïnitialiseerd op positie (" + liftX + ", " + liftY + ")");
        } else {
            System.out.println("[Simulator] WAARSCHUWING: Geen Schacht gevonden!");
        }

        // Registreer lift als listener
        if (lift != null) {
            hteClock.addListener(lift);
        }

        // === REGISTREER ALLE GASTEN EN KOP LIFT AAN ===
        for (Persoon p : hotel.getPersonen()) {
            // Registreer als listener op HTEClock
            if (p instanceof TickListener) {
                hteClock.addListener((TickListener) p);
            }

            // Als het een Gast is: geef hem een referentie naar de lift
            if (p instanceof Gast && lift != null) {
                ((Gast) p).setLift(lift);
                System.out.println("[Simulator] Gast '" + p.getNaam() + "' heeft lift-referentie gekregen");
            }
        }
    }

    public void start() {
        running = true;
        clock.start();
        hotelPanel.setRunning(true);
        System.out.println("[Simulator] Simulatie gestart");
    }

    public void pause() {
        running = false;
        clock.stop();
        hotelPanel.setRunning(false);
        System.out.println("[Simulator] Simulatie gepauzeerd");
    }

    public boolean isRunning() {
        return running;
    }

    public SimulationClock getClock() {
        return clock;
    }

    public HTEClock getHteClock() {
        return hteClock;
    }

    public Lift getLift() {
        return lift;
    }

    public void resetClock() {
        clock.reset();
        hteClock = new HTEClock();

        if (lift != null) {
            hteClock.addListener(lift);
        }

        for (Persoon p : hotel.getPersonen()) {
            if (p instanceof TickListener) {
                hteClock.addListener((TickListener) p);
            }
        }
    }

    /**
     * HOOFDMETHODE: Wordt aangeroepen door Timer in main
     * Dit triggert HTE-ticks als timing klopt
     */
    public void tick() {

        // Check of er een echte HTE-tick plaatsvindt
        if (running && clock.tick()) {
            System.out.println("[Simulator] HTE-tick #" + clock.getTimestep() + " | Lift Y: " + (lift != null ? String.format("%.1f", lift.getY()) : "N/A"));

            // Roep HTEClock.tick() aan (die roept alle listeners.onTick() aan)
            // Dit includes: Lift + Gasten
            hteClock.tick();
        }

        // UI altijd updaten (ook bij pauze)
        hotelPanel.repaint();
    }
}

package ui;

import model.Area;
import model.Hotel;
import model.Gast;
import model.Persoon;
import javax.swing.*;
import java.awt.*;
import java.util.List;

/**
 * Dit paneel is verantwoordelijk voor het visueel weergeven van het hotel.
 */
public class HotelPanel extends JPanel {

    private Hotel hotel;

    private final int VAKJE_GROOTTE = 50;

    // status van simulatie (optioneel)
    private boolean running = true;

    public HotelPanel(Hotel hotel) {
        this.hotel = hotel;
        updateDimensions();
    }

    public void setHotel(Hotel hotel) {
        this.hotel = hotel;
        updateDimensions();
        repaint();
    }

    // Simulator kan dit gebruiken
    public void setRunning(boolean running) {
        this.running = running;
    }

    private void updateDimensions() {
        if (hotel == null) return;

        int breedte = hotel.getBreedte() * VAKJE_GROOTTE;
        int hoogte = hotel.getHoogte() * VAKJE_GROOTTE;
        this.setPreferredSize(new Dimension(breedte, hoogte));
        revalidate(); // belangrijk voor UI refresh
    }

    @Override
    protected void paintComponent(Graphics g) {
        super.paintComponent(g);

        if (hotel == null) return;

        // Achtergrond (vloer)
        g.setColor(Color.WHITE);
        g.fillRect(0, 0, getWidth(), getHeight());

        // Bereken offsets om hotel in het midden te centreren
        int hotelBreedte = hotel.getBreedte() * VAKJE_GROOTTE;
        int hotelHoogte = hotel.getHoogte() * VAKJE_GROOTTE;
        int offsetX = (getWidth() - hotelBreedte) / 2;
        int offsetY = (getHeight() - hotelHoogte) / 2;

        // Areas tekenen
        List<Area> areas = hotel.getAreas();
        for (Area area : areas) {

            int x = (area.getX() - 1) * VAKJE_GROOTTE + offsetX;
            int y = (area.getY() - 1) * VAKJE_GROOTTE + offsetY;

            int breedte = area.getBreedte() * VAKJE_GROOTTE;
            int hoogte = area.getHoogte() * VAKJE_GROOTTE;

            // Achtergrond kleur
            g.setColor(getKleur(area));
            g.fillRect(x, y, breedte, hoogte);

            // Rand
            g.setColor(Color.DARK_GRAY);
            Graphics2D g2 = (Graphics2D) g;
            g2.setStroke(new BasicStroke(2));
            g.drawRect(x, y, breedte, hoogte);
            g2.setStroke(new BasicStroke(1));

            // Label
            g.setColor(Color.BLACK);
            g.setFont(new Font("Arial", Font.BOLD, 12));
            String label = getLabel(area);
            FontMetrics fm = g.getFontMetrics();

            int textX = x + (breedte - fm.stringWidth(label)) / 2;
            int textY = y + (hoogte + fm.getAscent()) / 2 - 2;

            g.drawString(label, textX, textY);
        }

        // Teken alle personen
        for (Persoon persoon : hotel.getPersonen()) {
            if (persoon instanceof Gast) {
                Gast gast = (Gast) persoon;
                // Gebruik doubles voor smooth pixel-gebaseerde coördinaten
                int px = (int)(gast.getX() * VAKJE_GROOTTE) + offsetX - 8;
                int py = (int)(gast.getY() * VAKJE_GROOTTE) + offsetY - 8;

                // Teken met gast's eigen kleur
                g.setColor(gast.getKleur());
                g.fillOval(px, py, 16, 16);

                // Teken rand (donkerder versie van dezelfde kleur)
                g.setColor(new Color(
                    Math.max(0, gast.getKleur().getRed() - 80),
                    Math.max(0, gast.getKleur().getGreen() - 80),
                    Math.max(0, gast.getKleur().getBlue() - 80)
                ));
                g.drawOval(px, py, 16, 16);

                // Teken naam als tooltip (optioneel, heel klein)
                g.setColor(Color.BLACK);
                g.setFont(new Font("Arial", Font.PLAIN, 8));
                g.drawString(gast.getNaam().substring(0, Math.min(3, gast.getNaam().length())), px + 2, py + 8);
            }
        }

        // toon status (pause/active)
        if (!running) {
            g.setColor(new Color(0, 0, 0, 150));
            g.fillRect(0, 0, getWidth(), getHeight());

            g.setColor(Color.WHITE);
            g.setFont(new Font("Arial", Font.BOLD, 30));
            g.drawString("PAUSED", getWidth() / 2 - 70, getHeight() / 2);
        }
    }

    private String getLabel(Area area) {
        // ...existing code...
        switch (area.getAreaType()) {
            case "Room":
                return area.getClassification() != null ?
                        area.getClassification().replace(" Star", "★") : "Kamer";
            case "Cinema": return "Bioscoop";
            case "Restaurant": return "Restaurant";
            case "Fitness": return "Fitness";
            case "Lobby": return "Lobby";
            case "Lift": return "Lift";
            case "Staircase": return "Trap";
            case "Storage": return "Opslag";
            default: return area.getAreaType();
        }
    }

    private Color getKleur(Area area) {
        switch (area.getAreaType()) {
            case "Room":
                String c = area.getClassification();
                if (c == null) return new Color(200, 230, 255);

                if (c.contains("1")) return new Color(200, 230, 255);
                if (c.contains("2")) return new Color(150, 200, 255);
                if (c.contains("3")) return new Color(100, 170, 255);
                if (c.contains("4")) return new Color(50, 130, 255);
                if (c.contains("5")) return new Color(0, 80, 200);

                return new Color(200, 230, 255);

            case "Lobby": return new Color(255, 220, 50);
            case "Lift": return new Color(255, 150, 0);
            case "Staircase": return new Color(100, 200, 100);
            case "Restaurant": return new Color(255, 100, 100);
            case "Cinema": return new Color(200, 100, 200);
            case "Fitness": return new Color(100, 220, 180);
            case "Storage": return new Color(180, 140, 100);
            default: return Color.WHITE;
        }
    }
}

package ui;

import model.Area;
import model.Hotel;
import model.Gast;
import model.Persoon;
import model.Lift;
import javax.swing.*;
import java.awt.*;
import java.util.List;

/**
 * Dit paneel is verantwoordelijk voor het visueel weergeven van het hotel.
 */
public class HotelPanel extends JPanel {

    private Hotel hotel;
    private Lift lift;  // Referentie naar de lift om deze te tekenen

    private final int VAKJE_GROOTTE = 50;

    // status van simulatie (optioneel)
    private boolean running = true;

    public HotelPanel(Hotel hotel) {
        this.hotel = hotel;
        updateDimensions();
    }

    public void setHotel(Hotel hotel) {
        this.hotel = hotel;
        updateDimensions();
        repaint();
    }

    public void setLift(Lift lift) {
        this.lift = lift;
    }

    // Simulator kan dit gebruiken
    public void setRunning(boolean running) {
        this.running = running;
    }

    private void updateDimensions() {
        if (hotel == null) return;

        int breedte = hotel.getBreedte() * VAKJE_GROOTTE;
        int hoogte = hotel.getHoogte() * VAKJE_GROOTTE;
        this.setPreferredSize(new Dimension(breedte, hoogte));
        revalidate(); // belangrijk voor UI refresh
    }

    @Override
    protected void paintComponent(Graphics g) {
        super.paintComponent(g);

        if (hotel == null) return;

        // Achtergrond (vloer)
        g.setColor(Color.WHITE);
        g.fillRect(0, 0, getWidth(), getHeight());

        // Bereken offsets om hotel in het midden te centreren
        int hotelBreedte = hotel.getBreedte() * VAKJE_GROOTTE;
        int hotelHoogte = hotel.getHoogte() * VAKJE_GROOTTE;
        int offsetX = (getWidth() - hotelBreedte) / 2;
        int offsetY = (getHeight() - hotelHoogte) / 2;

        // Areas tekenen
        List<Area> areas = hotel.getAreas();
        for (Area area : areas) {
            // SKIP: De 1x1 Lift area - deze wordt dynamisch getekend!
            if (area.getAreaType().equals("Lift")) {
                continue;  // Teken NIET op vaste positie
            }

            int x = (area.getX() - 1) * VAKJE_GROOTTE + offsetX;
            int y = (area.getY() - 1) * VAKJE_GROOTTE + offsetY;

            int breedte = area.getBreedte() * VAKJE_GROOTTE;
            int hoogte = area.getHoogte() * VAKJE_GROOTTE;

            // Achtergrond kleur
            g.setColor(getKleur(area));
            g.fillRect(x, y, breedte, hoogte);

            // Rand
            g.setColor(Color.DARK_GRAY);
            Graphics2D g2 = (Graphics2D) g;
            g2.setStroke(new BasicStroke(2));
            g.drawRect(x, y, breedte, hoogte);
            g2.setStroke(new BasicStroke(1));

            // Label
            g.setColor(Color.BLACK);
            g.setFont(new Font("Arial", Font.BOLD, 12));
            String label = getLabel(area);
            FontMetrics fm = g.getFontMetrics();

            int textX = x + (breedte - fm.stringWidth(label)) / 2;
            int textY = y + (hoogte + fm.getAscent()) / 2 - 2;

            g.drawString(label, textX, textY);
        }

        // === TEKEN LIFT (BEWEGEND OBJECT) ===
        // Dit vervangt de statische 1x1 Lift area uit Areas!
        if (lift != null) {
            // Teken lift als 1x1 vakje
            int liftX = (int)(lift.getX() * VAKJE_GROOTTE) + offsetX - VAKJE_GROOTTE/2;
            int liftY = (int)(lift.getY() * VAKJE_GROOTTE) + offsetY - VAKJE_GROOTTE/2;

            // Teken lift als oranje vierkant (VAKJE_GROOTTE groot)
            g.setColor(new Color(200, 100, 0));  // Oranje
            g.fillRect(liftX, liftY, VAKJE_GROOTTE, VAKJE_GROOTTE);

            // Rand
            g.setColor(Color.BLACK);
            Graphics2D g2d = (Graphics2D) g;
            g2d.setStroke(new BasicStroke(2));
            g.drawRect(liftX, liftY, VAKJE_GROOTTE, VAKJE_GROOTTE);

            // Teken "L" erin (groot)
            g.setColor(Color.WHITE);
            g.setFont(new Font("Arial", Font.BOLD, 30));
            FontMetrics fm = g.getFontMetrics();
            int lx = liftX + (VAKJE_GROOTTE - fm.stringWidth("L")) / 2;
            int ly = liftY + (VAKJE_GROOTTE + fm.getAscent()) / 2 - 5;
            g.drawString("L", lx, ly);
        }

        // Teken alle personen
        for (Persoon persoon : hotel.getPersonen()) {
            if (persoon instanceof Gast) {
                Gast gast = (Gast) persoon;
                // Gebruik doubles voor smooth pixel-gebaseerde coördinaten
                int px = (int)(gast.getX() * VAKJE_GROOTTE) + offsetX - 8;
                int py = (int)(gast.getY() * VAKJE_GROOTTE) + offsetY - 8;

                // Teken met gast's eigen kleur
                g.setColor(gast.getKleur());
                g.fillOval(px, py, 16, 16);

                // Teken rand (donkerder versie van dezelfde kleur)
                g.setColor(new Color(
                    Math.max(0, gast.getKleur().getRed() - 80),
                    Math.max(0, gast.getKleur().getGreen() - 80),
                    Math.max(0, gast.getKleur().getBlue() - 80)
                ));
                g.drawOval(px, py, 16, 16);

                // Teken naam als tooltip (optioneel, heel klein)
                g.setColor(Color.BLACK);
                g.setFont(new Font("Arial", Font.PLAIN, 8));
                g.drawString(gast.getNaam().substring(0, Math.min(3, gast.getNaam().length())), px + 2, py + 8);
            }
        }

        // toon status (pause/active)
        if (!running) {
            g.setColor(new Color(0, 0, 0, 150));
            g.fillRect(0, 0, getWidth(), getHeight());

            g.setColor(Color.WHITE);
            g.setFont(new Font("Arial", Font.BOLD, 30));
            g.drawString("PAUSED", getWidth() / 2 - 70, getHeight() / 2);
        }
    }

    private String getLabel(Area area) {
        // ...existing code...
        switch (area.getAreaType()) {
            case "Room":
                return area.getClassification() != null ?
                        area.getClassification().replace(" Star", "★") : "Kamer";
            case "Cinema": return "Bioscoop";
            case "Restaurant": return "Restaurant";
            case "Fitness": return "Fitness";
            case "Lobby": return "Lobby";
            case "Schacht": return "Schacht";
            case "Lift": return "Lift";
            case "Staircase": return "Trap";
            case "Storage": return "Opslag";
            default: return area.getAreaType();
        }
    }

    private Color getKleur(Area area) {
        switch (area.getAreaType()) {
            case "Room":
                String c = area.getClassification();
                if (c == null) return new Color(200, 230, 255);

                if (c.contains("1")) return new Color(200, 230, 255);
                if (c.contains("2")) return new Color(150, 200, 255);
                if (c.contains("3")) return new Color(100, 170, 255);
                if (c.contains("4")) return new Color(50, 130, 255);
                if (c.contains("5")) return new Color(0, 80, 200);

                return new Color(200, 230, 255);

            case "Lobby": return new Color(255, 220, 50);
            case "Schacht": return new Color(220, 220, 220);  // Grijze schacht
            case "Lift": return new Color(255, 150, 0);
            case "Staircase": return new Color(100, 200, 100);
            case "Restaurant": return new Color(255, 100, 100);
            case "Cinema": return new Color(200, 100, 200);
            case "Fitness": return new Color(100, 220, 180);
            case "Storage": return new Color(180, 140, 100);
            default: return Color.WHITE;
        }
    }
}

import model.Hotel;
import model.LayoutLoader;
import ui.HotelPanel;
import model.Simulator;
import model.Gast;
import model.SimulationClock;
import model.HTEClock;

import javax.swing.*;
import java.io.File;
import java.util.Arrays;

/**
 * De MainUI klasse is het startpunt van de applicatie.
 * Het regelt de GUI (Swing), de interactie met de gebruiker en de aansturing van de simulator.
 */
public class main {

    // --- VARIABELEN (State) ---
    private static HotelPanel hotelPanel;      // Het canvas waarop het hotel getekend wordt
    private static JComboBox<String> layoutDropdown; // Keuzemenu voor de JSON-bestanden
    private static JLabel statusLabel;         // Tekstbalk onderin voor statusberichten
    private static JLabel timestepLabel;       // Toont de huidige tijdstap (HTE)
    private static JButton startPauseButton;   // De knop die wisselt tussen Start en Pause
    private static Simulator simulator;        // De 'hersenen' van de simulatie (logica)

    /** * US2.3: De Timer is de 'hartslag' van de UI.
     * We maken er een variabele van zodat de slider de hartslag kan versnellen of vertragen.
     */
    private static Timer simulationTimer;

    public static void main(String[] args) {
        // SwingUtilities zorgt ervoor dat de UI veilig op de 'Event Dispatch Thread' draait.
        // Dit voorkomt dat je scherm vastloopt (freezes).
        SwingUtilities.invokeLater(() -> {
            try {
                // --- FRAME INITIALISATIE ---
                JFrame frame = new JFrame("Hotel Simulator");
                frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE); // Stopt programma bij afsluiten

                // ControlPanel is de grijze balk bovenin met alle knoppen.
                JPanel controlPanel = new JPanel();
                controlPanel.add(new JLabel("Selecteer layout: "));

                // Haal de lijst met .json bestanden op uit de map 'layouts'.
                String[] layouts = getAvailableLayouts();
                layoutDropdown = new JComboBox<>(layouts);
                controlPanel.add(layoutDropdown);

                // --- KNOPPEN LOGICA ---

                // Laden-knop: roept de methode aan om een nieuw hotel in te laden.
                JButton loadButton = new JButton("Laden");
                loadButton.addActionListener(e -> loadLayout());
                controlPanel.add(loadButton);

                // Start/Pause-knop:
                startPauseButton = new JButton("Start");
                startPauseButton.addActionListener(e -> {
                    // Check of de simulator op dit moment draait
                    if (!simulator.isRunning()) {
                        simulator.start(); // Logische start
                        startPauseButton.setText("Pause"); // Verander tekst op knop
                        statusLabel.setText("Simulatie actief");
                    } else {
                        simulator.pause(); // Logische pauze
                        startPauseButton.setText("Resume"); // Verander tekst op knop
                        statusLabel.setText("Simulatie gepauzeerd");
                    }
                });
                controlPanel.add(startPauseButton);

                // --- US2.3: DE SNELHEID SLIDER ---
                // We maken een label om de huidige snelheid in tekst te tonen (ms).
                JLabel speedLabel = new JLabel("Delay: 500ms");

                /**
                 * JSlider(min, max, startwaarde).
                 * We gebruiken 50ms als snelste (1000ms / 50 = 20 ticks per sec).
                 * We gebruiken 1000ms als langzaamste (1 tick per sec).
                 */
                JSlider speedSlider = new JSlider(50, 1000, 500);

                // ChangeListener: wordt uitgevoerd zodra je het schuifje beweegt.
                speedSlider.addChangeListener(e -> {
                    int delay = speedSlider.getValue(); // Haal de nieuwe waarde uit de slider

                    if (simulationTimer != null) {
                        // Cruciaal: We vertellen de Timer dat hij minder lang moet wachten tussen ticks.
                        simulationTimer.setDelay(delay);
                    }
                    // Werk de tekst op het scherm bij.
                    speedLabel.setText("Delay: " + delay + "ms");
                });

                controlPanel.add(speedLabel);
                controlPanel.add(speedSlider);

                // --- LABELS VOOR INFORMATIE ---
                statusLabel = new JLabel("Hotel laden...");
                controlPanel.add(statusLabel);

                timestepLabel = new JLabel("Timestep: 0");
                controlPanel.add(timestepLabel);

                // --- EERSTE SETUP ---
                // We laden direct het eerste hotel uit de lijst zodat het scherm niet leeg is.
                Hotel hotel = LayoutLoader.laadLayout("layouts/" + layouts[0]);
                hotelPanel = new HotelPanel(hotel); // Maak het teken-veld aan
                addTestGuests(hotel); // Zet Alice, Bob en Charlie in het hotel

                // Maak de simulator-engine aan.
                simulator = new Simulator(hotel, hotelPanel);
                simulator.pause(); // De simulatie staat stil tot de gebruiker op Start klikt.

                // Voeg de onderdelen toe aan het hoofdvenster.
                frame.add(controlPanel, "North"); // Knoppen boven
                frame.add(hotelPanel, "Center"); // Hotel in het midden
                frame.pack(); // Maak venster precies groot genoeg
                frame.setLocationRelativeTo(null); // Centreer venster op scherm
                frame.setVisible(true); // Toon het venster

                /**
                 * DE KLOK (Timer) - HTE TICK ARCHITECTUUR:
                 * De timer 'vuurt' elke 50ms (UI refresh rate).
                 * De simulator bepaalt zelf via SimulationClock wanneer een echte HTE-tick moet plaatsvinden.
                 */
                simulationTimer = new Timer(50, e -> {
                    // Roep simulator.tick() aan - dit bepaalt intern of een HTE-tick nodig is
                    simulator.tick();

                    // Update UI met huidige timestep (alleen weergeven)
                    timestepLabel.setText("Timestep: " + simulator.getClock().getTimestep());
                });
                simulationTimer.start(); // De timer begint met 'lopen' op de achtergrond.

            } catch (Exception e) {
                // Foutopsporing: als er iets misgaat (bijv. bestand niet gevonden), zie je dat in de console.
                System.out.println("Fout: " + e.getMessage());
                e.printStackTrace();
            }
        });
    }

    /**
     * getAvailableLayouts:
     * Deze methode kijkt in de map 'layouts' en filtert alle bestanden die eindigen op .json.
     * Zo hoef je de namen van de bestanden niet hardcoded in je code te zetten.
     */
    private static String[] getAvailableLayouts() {
        File layoutDir = new File("layouts");
        String[] layouts = layoutDir.list((dir, name) -> name.endsWith(".json"));
        if (layouts == null || layouts.length == 0) {
            throw new RuntimeException("Fout: Geen .json layouts gevonden in de map.");
        }
        Arrays.sort(layouts); // Zet ze op alfabetische volgorde
        return layouts;
    }

    /**
     * loadLayout:
     * Wordt aangeroepen als je op de 'Laden' knop klikt.
     * Het 'ververst' het huidige hotel met een nieuw bestand.
     */
    private static void loadLayout() {
        try {
            // Pak de geselecteerde naam uit de dropdown
            String selectedLayout = (String) layoutDropdown.getSelectedItem();

            // Gebruik de LayoutLoader om de JSON te vertalen naar een Hotel-object
            Hotel newHotel = LayoutLoader.laadLayout("layouts/" + selectedLayout);

            // Geef het nieuwe hotel door aan het HotelPanel zodat de tekening verandert
            hotelPanel.setHotel(newHotel);

            addTestGuests(newHotel); // Zet de gasten weer terug op hun startpositie

            // Maak de simulator helemaal opnieuw aan voor het nieuwe hotel.
            simulator = new Simulator(newHotel, hotelPanel);
            simulator.resetClock(); // Belangrijk: De klok moet weer op 0 beginnen.
            simulator.pause(); // Het nieuwe hotel begint altijd gepauzeerd.

            // Reset de Start-knop tekst
            if (startPauseButton != null) {
                startPauseButton.setText("Start");
            }
            statusLabel.setText("Nieuw hotel geladen: " + selectedLayout);

        } catch (Exception e) {
            statusLabel.setText("Fout bij laden: " + e.getMessage());
        }
    }

    /**
     * addTestGuests:
     * Omdat we nog geen reserveringssysteem hebben, voegen we handmatig
     * drie Gast-objecten toe aan de lijst met personen in het Hotel.
     */
    private static void addTestGuests(Hotel hotel) {
        // Maak Alice aan op positie (2,2)
        Gast gast1 = new Gast("Alice", 2, 2);
        gast1.setGridBounds(hotel.getBreedte(), hotel.getHoogte());
        gast1.setHotel(hotel);  // Geef gast de hotel areas
        hotel.addPersoon(gast1);

        // Doe hetzelfde voor Bob en Charlie
        Gast gast2 = new Gast("Bob", 3, 3);
        gast2.setGridBounds(hotel.getBreedte(), hotel.getHoogte());
        gast2.setHotel(hotel);
        hotel.addPersoon(gast2);

        Gast gast3 = new Gast("Charlie", 1, 1);
        gast3.setGridBounds(hotel.getBreedte(), hotel.getHoogte());
        gast3.setHotel(hotel);
        hotel.addPersoon(gast3);
    }
}

import model.Hotel;
import model.LayoutLoader;
import ui.HotelPanel;
import model.Simulator;
import model.Gast;
import model.SimulationClock;
import model.HTEClock;

import javax.swing.*;
import java.io.File;
import java.util.Arrays;

/**
 * De MainUI klasse is het startpunt van de applicatie.
 * Het regelt de GUI (Swing), de interactie met de gebruiker en de aansturing van de simulator.
 */
public class main {

    // --- VARIABELEN (State) ---
    private static HotelPanel hotelPanel;      // Het canvas waarop het hotel getekend wordt
    private static JComboBox<String> layoutDropdown; // Keuzemenu voor de JSON-bestanden
    private static JLabel statusLabel;         // Tekstbalk onderin voor statusberichten
    private static JLabel timestepLabel;       // Toont de huidige tijdstap (HTE)
    private static JButton startPauseButton;   // De knop die wisselt tussen Start en Pause
    private static Simulator simulator;        // De 'hersenen' van de simulatie (logica)

    /** * US2.3: De Timer is de 'hartslag' van de UI.
     * We maken er een variabele van zodat de slider de hartslag kan versnellen of vertragen.
     */
    private static Timer simulationTimer;

    public static void main(String[] args) {
        // SwingUtilities zorgt ervoor dat de UI veilig op de 'Event Dispatch Thread' draait.
        // Dit voorkomt dat je scherm vastloopt (freezes).
        SwingUtilities.invokeLater(() -> {
            try {
                // --- FRAME INITIALISATIE ---
                JFrame frame = new JFrame("Hotel Simulator");
                frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE); // Stopt programma bij afsluiten

                // ControlPanel is de grijze balk bovenin met alle knoppen.
                JPanel controlPanel = new JPanel();
                controlPanel.add(new JLabel("Selecteer layout: "));

                // Haal de lijst met .json bestanden op uit de map 'layouts'.
                String[] layouts = getAvailableLayouts();
                layoutDropdown = new JComboBox<>(layouts);
                controlPanel.add(layoutDropdown);

                // --- KNOPPEN LOGICA ---

                // Laden-knop: roept de methode aan om een nieuw hotel in te laden.
                JButton loadButton = new JButton("Laden");
                loadButton.addActionListener(e -> loadLayout());
                controlPanel.add(loadButton);

                // Start/Pause-knop:
                startPauseButton = new JButton("Start");
                startPauseButton.addActionListener(e -> {
                    // Check of de simulator op dit moment draait
                    if (!simulator.isRunning()) {
                        simulator.start(); // Logische start
                        startPauseButton.setText("Pause"); // Verander tekst op knop
                        statusLabel.setText("Simulatie actief");
                    } else {
                        simulator.pause(); // Logische pauze
                        startPauseButton.setText("Resume"); // Verander tekst op knop
                        statusLabel.setText("Simulatie gepauzeerd");
                    }
                });
                controlPanel.add(startPauseButton);

                // --- US2.3: DE SNELHEID SLIDER ---
                // We maken een label om de huidige snelheid in tekst te tonen (ms).
                JLabel speedLabel = new JLabel("Tick Interval: 100ms");

                /**
                 * JSlider(min, max, startwaarde).
                 * We gebruiken 50ms als snelste (meer ticks per seconde).
                 * We gebruiken 1000ms als langzaamste (1 tick per sec).
                 */
                JSlider speedSlider = new JSlider(50, 1000, 100);

                // ChangeListener: wordt uitgevoerd zodra je het schuifje beweegt.
                speedSlider.addChangeListener(e -> {
                    int newInterval = speedSlider.getValue(); // Haal de nieuwe waarde uit de slider

                    if (simulator != null) {
                        // Pas de tick-interval aan in de SimulationClock
                        simulator.getClock().setTickInterval(newInterval);
                    }
                    // Werk de tekst op het scherm bij.
                    speedLabel.setText("Tick Interval: " + newInterval + "ms");
                });

                controlPanel.add(speedLabel);
                controlPanel.add(speedSlider);

                // --- LABELS VOOR INFORMATIE ---
                statusLabel = new JLabel("Hotel laden...");
                controlPanel.add(statusLabel);

                timestepLabel = new JLabel("Timestep: 0");
                controlPanel.add(timestepLabel);

                // --- EERSTE SETUP ---
                // We laden direct het eerste hotel uit de lijst zodat het scherm niet leeg is.
                Hotel hotel = LayoutLoader.laadLayout("layouts/" + layouts[0]);
                hotelPanel = new HotelPanel(hotel); // Maak het teken-veld aan
                addTestGuests(hotel); // Zet Alice, Bob en Charlie in het hotel

                // Maak de simulator-engine aan.
                simulator = new Simulator(hotel, hotelPanel);
                simulator.pause(); // De simulatie staat stil tot de gebruiker op Start klikt.

                // Voeg de onderdelen toe aan het hoofdvenster.
                frame.add(controlPanel, "North"); // Knoppen boven
                frame.add(hotelPanel, "Center"); // Hotel in het midden
                frame.pack(); // Maak venster precies groot genoeg
                frame.setLocationRelativeTo(null); // Centreer venster op scherm
                frame.setVisible(true); // Toon het venster

                /**
                 * DE KLOK (Timer) - HTE TICK ARCHITECTUUR:
                 * De timer 'vuurt' elke 50ms (UI refresh rate).
                 * De simulator bepaalt zelf via SimulationClock wanneer een echte HTE-tick moet plaatsvinden.
                 */
                simulationTimer = new Timer(50, e -> {
                    // Roep simulator.tick() aan - dit bepaalt intern of een HTE-tick nodig is
                    simulator.tick();

                    // Update UI met huidige timestep (alleen weergeven)
                    timestepLabel.setText("Timestep: " + simulator.getClock().getTimestep());
                });
                simulationTimer.start(); // De timer begint met 'lopen' op de achtergrond.

            } catch (Exception e) {
                // Foutopsporing: als er iets misgaat (bijv. bestand niet gevonden), zie je dat in de console.
                System.out.println("Fout: " + e.getMessage());
                e.printStackTrace();
            }
        });
    }

    /**
     * getAvailableLayouts:
     * Deze methode kijkt in de map 'layouts' en filtert alle bestanden die eindigen op .json.
     * Zo hoef je de namen van de bestanden niet hardcoded in je code te zetten.
     */
    private static String[] getAvailableLayouts() {
        File layoutDir = new File("layouts");
        String[] layouts = layoutDir.list((dir, name) -> name.endsWith(".json"));
        if (layouts == null || layouts.length == 0) {
            throw new RuntimeException("Fout: Geen .json layouts gevonden in de map.");
        }
        Arrays.sort(layouts); // Zet ze op alfabetische volgorde
        return layouts;
    }

    /**
     * loadLayout:
     * Wordt aangeroepen als je op de 'Laden' knop klikt.
     * Het 'ververst' het huidige hotel met een nieuw bestand.
     */
    private static void loadLayout() {
        try {
            // Pak de geselecteerde naam uit de dropdown
            String selectedLayout = (String) layoutDropdown.getSelectedItem();

            // Gebruik de LayoutLoader om de JSON te vertalen naar een Hotel-object
            Hotel newHotel = LayoutLoader.laadLayout("layouts/" + selectedLayout);

            // Geef het nieuwe hotel door aan het HotelPanel zodat de tekening verandert
            hotelPanel.setHotel(newHotel);

            addTestGuests(newHotel); // Zet de gasten weer terug op hun startpositie

            // Maak de simulator helemaal opnieuw aan voor het nieuwe hotel.
            simulator = new Simulator(newHotel, hotelPanel);
            simulator.resetClock(); // Belangrijk: De klok moet weer op 0 beginnen.
            simulator.pause(); // Het nieuwe hotel begint altijd gepauzeerd.

            // Reset de Start-knop tekst
            if (startPauseButton != null) {
                startPauseButton.setText("Start");
            }
            statusLabel.setText("Nieuw hotel geladen: " + selectedLayout);

        } catch (Exception e) {
            statusLabel.setText("Fout bij laden: " + e.getMessage());
        }
    }

    /**
     * addTestGuests:
     * Omdat we nog geen reserveringssysteem hebben, voegen we handmatig
     * drie Gast-objecten toe aan de lijst met personen in het Hotel.
     */
    private static void addTestGuests(Hotel hotel) {
        // Maak Alice aan op positie (2,2)
        Gast gast1 = new Gast("Alice", 2, 2);
        gast1.setGridBounds(hotel.getBreedte(), hotel.getHoogte());
        gast1.setHotel(hotel);  // Geef gast de hotel areas
        hotel.addPersoon(gast1);

        // Doe hetzelfde voor Bob en Charlie
        Gast gast2 = new Gast("Bob", 3, 3);
        gast2.setGridBounds(hotel.getBreedte(), hotel.getHoogte());
        gast2.setHotel(hotel);
        hotel.addPersoon(gast2);

        Gast gast3 = new Gast("Charlie", 1, 1);
        gast3.setGridBounds(hotel.getBreedte(), hotel.getHoogte());
        gast3.setHotel(hotel);
        hotel.addPersoon(gast3);
    }
}
